### Pass Additional Arguments to Next.js Server Action using Bind

Source: https://github.com/vercel/next.js/blob/canary/docs/01-app/02-guides/forms.mdx

This code illustrates how to pass extra arguments, such as a `userId`, to a Server Function using JavaScript's `bind` method within a Next.js Client Component. The `updateUserWithId` function, created by binding `userId` to `updateUser`, is then assigned to the form's `action` attribute, enabling the Server Action to receive context-specific data alongside form data.

```tsx
'use client'

import { updateUser } from './actions'

export function UserProfile({ userId }: { userId: string }) {
  const updateUserWithId = updateUser.bind(null, userId)

  return (
    <form action={updateUserWithId}>
      <input type="text" name="name" />
      <button type="submit">Update User Name</button>
    </form>
  )
}
```

